@strawberry.type
class Review:
    id: int
    author: str
    rating: int
    comment: Optional[str]
    created_at: dt.datetime


@strawberry.type
class Seller:
    id: int
    name: str
    url: Optional[str]


@strawberry.type
class Category:
    id: int
    name: str


@strawberry.type
class Image:
    id: int
    url: str
    alt_text: Optional[str]


@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: float
    created_at: dt.datetime

    @strawberry.field
    def reviews(self, info) -> List[Review]:
        return [
            Review(
                id=r.id,
                author=r.author,
                rating=r.rating,
                comment=r.comment,
                created_at=r.created_at,
            )
            for r in self._orm.reviews
        ]

    @strawberry.field
    def sellers(self, info) -> List[Seller]:
        return [Seller(id=s.id, name=s.name, url=s.url) for s in self._orm.sellers]

    @strawberry.field
    def categories(self, info) -> List[Category]:
        return [Category(id=c.id, name=c.name) for c in self._orm.categories]

    @strawberry.field
    def images(self, info) -> List[Image]:
        return [Image(id=i.id, url=i.url, alt_text=i.alt_text) for i in self._orm.images]


def product_from_model(model: ProductModel) -> Product:
    obj = Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=model.price,
        created_at=model.created_at,
    )
    obj._orm = model
    return obj


def get_db() -> Session:
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()


@strawberry.type
class Query:
    @strawberry.field
    def products(self, info) -> List[Product]:
        db: Session = next(get_db())
        try:
            products = (
                db.query(ProductModel)
                .options(
                    joinedload(ProductModel.reviews),
                    joinedload(ProductModel.sellers),
                    joinedload(ProductModel.categories),
                    joinedload(ProductModel.images),
                )
                .all()
            )
            return [product_from_model(p) for p in products]
        finally:
            db.close()

    @strawberry.field
    def product(self, info, id: int) -> Optional[Product]:
        db: Session = next(get_db())
        try:
            product = (
                db.query(ProductModel)
                .options(
                    joinedload(ProductModel.reviews),
                    joinedload(ProductModel.sellers),
                    joinedload(ProductModel.categories),
                    joinedload(ProductModel.images),
                )
                .filter(ProductModel.id == id)
                .first()
            )
            return product_from_model(product) if product else None
        finally:
            db.close()


schema = strawberry.Schema(query=Query)

app = FastAPI()
graphql_app = GraphQLRouter(schema)
app.include_router(graphql_app, prefix="/graphql")